'use client';

import React, { useState } from 'react';
import { useAppContext } from '@/context/AppContext';
import { supabase } from '@/lib/supabase';
import { format, parseISO } from 'date-fns';
import { es } from 'date-fns/locale';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Plus, 
  Minus, 
  History, 
  Calendar as CalendarIcon,
  Store,
  CalendarDays,
  LogOut,
  AlertCircle
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import Link from 'next/link';

export default function Dashboard() {
  const { 
    user, 
    loading, 
    transactions, 
    timeFilter, 
    setTimeFilter,
    currentBusinessId,
    setCurrentBusinessId,
    businesses,
    refreshData 
  } = useAppContext();

  const [modalType, setModalType] = useState<'income' | 'expense' | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  // Calculations
  const totalIncome = transactions
    .filter(t => t.type === 'income')
    .reduce((s, t) => s + (parseFloat(t.amount) || 0), 0);

  const totalExpense = transactions
    .filter(t => t.type === 'expense')
    .reduce((s, t) => s + (parseFloat(t.amount) || 0), 0);

  const profit = totalIncome - totalExpense;

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('es-CO', { style: 'currency', currency: 'COP', maximumFractionDigits: 0 }).format(val);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    window.location.reload();
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-slate-950">
        <div className="w-10 h-10 border-4 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin"></div>
      </div>
    );
  }

  if (!user) {
    if (typeof window !== 'undefined') window.location.href = '/login';
    return null;
  }

  return (
    <div className="min-h-screen bg-slate-950 pb-24">
      {/* Navbar */}
      <nav className="sticky top-0 z-40 bg-slate-950/80 backdrop-blur-xl border-b border-slate-900 p-4">
        <div className="max-w-xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center font-black text-white text-xl italic shadow-lg shadow-emerald-900/20">
              R
            </div>
            <div>
              <p className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.2em]">{user.role}</p>
              <h1 className="font-bold text-slate-100">Hola, {user.name.split(' ')[0]}</h1>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <Link href="/shifts" title="Mi Horario" className="w-10 h-10 bg-slate-900 border border-slate-800 rounded-xl flex items-center justify-center text-slate-400 hover:text-white transition-all">
              <CalendarDays size={20} />
            </Link>
            <button onClick={handleLogout} title="Cerrar Sesión" className="w-10 h-10 bg-slate-900 border border-slate-800 rounded-xl flex items-center justify-center text-slate-400 hover:text-red-400 transition-all">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-xl mx-auto p-4 space-y-6 mt-4">
        {/* Balance Card */}
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="relative overflow-hidden bg-gradient-to-br from-indigo-600 to-violet-700 p-8 rounded-[2.5rem] shadow-2xl shadow-indigo-900/40"
        >
          <div className="absolute top-[-20%] right-[-10%] w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
          <div className="relative z-10">
            <div className="flex items-center gap-2 text-indigo-100/60 mb-2 uppercase text-[10px] font-black tracking-widest">
              <TrendingUp size={12} />
              Utilidad Neta Total
            </div>
            <h2 className="text-4xl md:text-5xl font-black text-white tracking-tight mb-6">
              {formatCurrency(profit)}
            </h2>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-white/10 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                <p className="text-[10px] font-bold text-indigo-100/50 uppercase mb-1">Ingresos</p>
                <p className="text-lg font-bold text-emerald-300">{formatCurrency(totalIncome)}</p>
              </div>
              <div className="bg-white/10 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                <p className="text-[10px] font-bold text-indigo-100/50 uppercase mb-1">Gastos</p>
                <p className="text-lg font-bold text-rose-300">{formatCurrency(totalExpense)}</p>
              </div>
            </div>
          </div>
        </motion.div>

        {/* Quick Actions */}
        <div className="grid grid-cols-2 gap-4">
          <button 
            onClick={() => setModalType('income')}
            className="flex items-center justify-center gap-3 bg-emerald-500/10 border border-emerald-500/20 p-5 rounded-3xl hover:bg-emerald-500/20 transition-all group"
          >
            <div className="w-10 h-10 bg-emerald-500 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-900/40 group-hover:scale-110 transition-transform">
              <Plus size={24} />
            </div>
            <span className="font-bold text-emerald-400">VENTA</span>
          </button>
          <button 
            onClick={() => setModalType('expense')}
            className="flex items-center justify-center gap-3 bg-rose-500/10 border border-rose-500/20 p-5 rounded-3xl hover:bg-rose-500/20 transition-all group"
          >
            <div className="w-10 h-10 bg-rose-500 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-rose-900/40 group-hover:scale-110 transition-transform">
              <Minus size={24} />
            </div>
            <span className="font-bold text-rose-400">GASTO</span>
          </button>
        </div>

        {/* Recent Activity */}
        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h3 className="text-sm font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
              <History size={16} />
              Actividad Reciente
            </h3>
            <div className="flex gap-2">
              {['daily', 'weekly', 'monthly'].map((f) => (
                <button
                  key={f}
                  onClick={() => setTimeFilter(f as any)}
                  className={`text-[10px] font-bold uppercase px-2 py-1 rounded-md transition-all ${
                    timeFilter === f ? 'bg-slate-800 text-slate-100' : 'text-slate-600 hover:text-slate-400'
                  }`}
                >
                  {f === 'daily' ? 'Hoy' : f === 'weekly' ? 'Sem' : 'Mes'}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-slate-900/50 border border-slate-900 rounded-[2rem] overflow-hidden">
            {transactions.length === 0 ? (
              <div className="p-12 text-center text-slate-600">
                <AlertCircle size={32} className="mx-auto mb-3 opacity-20" />
                <p className="text-sm">Sin movimientos registrados</p>
              </div>
            ) : (
              <div className="divide-y divide-slate-800/50">
                {transactions.map((t, i) => (
                  <motion.div 
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    key={t.id} 
                    className="p-5 flex items-center justify-between hover:bg-slate-800/30 transition-all"
                  >
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${
                        t.type === 'income' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'
                      }`}>
                        {t.type === 'income' ? <TrendingUp size={20} /> : <TrendingDown size={20} />}
                      </div>
                      <div>
                        <p className="font-bold text-slate-200 capitalize">{t.type === 'income' ? 'Venta' : 'Gasto'}</p>
                        <p className="text-[10px] text-slate-500 font-medium">{format(parseISO(t.date), "dd MMM · HH:mm", { locale: es })}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className={`font-black text-lg ${t.type === 'income' ? 'text-emerald-400' : 'text-rose-400'}`}>
                        {t.type === 'income' ? '+' : '-'}{formatCurrency(t.amount)}
                      </p>
                    </div>
                  </motion.div>
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Basic Transaction Modal Overlay */}
      <AnimatePresence>
        {modalType && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-slate-950/90 backdrop-blur-md flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              className="w-full max-w-md bg-slate-900 border border-slate-800 rounded-[2.5rem] p-8 shadow-2xl"
            >
              <h2 className="text-2xl font-bold mb-6 flex items-center gap-3">
                {modalType === 'income' ? (
                  <><Plus className="text-emerald-500" /> Registrar Venta</>
                ) : (
                  <><Minus className="text-rose-500" /> Registrar Gasto</>
                )}
              </h2>
              
              <form className="space-y-6" onSubmit={(e) => {
                e.preventDefault();
                setModalType(null);
                refreshData();
              }}>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest px-1">Monto (COP)</label>
                  <input 
                    type="number" 
                    placeholder="0" 
                    required 
                    className="w-full bg-slate-800 border-none rounded-2xl p-4 text-2xl font-black text-white focus:ring-2 ring-indigo-500 outline-none transition-all"
                  />
                </div>
                
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest px-1">Negocio</label>
                  <div className="w-full bg-slate-800/50 p-4 rounded-2xl flex items-center gap-3 text-slate-400">
                    <Store size={18} />
                    <span className="font-medium">Negocio Actual</span>
                  </div>
                </div>

                <div className="flex gap-3 pt-4">
                  <button 
                    type="button" 
                    onClick={() => setModalType(null)}
                    className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 font-bold py-4 rounded-2xl transition-all"
                  >
                    CANCELAR
                  </button>
                  <button 
                    type="submit"
                    className={`flex-1 font-bold py-4 rounded-2xl transition-all text-white shadow-lg ${
                      modalType === 'income' 
                        ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/20' 
                        : 'bg-rose-600 hover:bg-rose-500 shadow-rose-900/20'
                    }`}
                  >
                    GUARDAR
                  </button>
                </div>
              </form>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
